#include <stdio.h>
#include <string.h>

int main() {
    char v[1000];
    scanf("%s", v);
    char c = v[0];
    for (int i = 1; v[i] != '\0'; i++) {
        if (v[i] > c) {
            c = v[i];
        }
    }
    int count = 0;
    for (int i = 0; v[i] != '\0'; i++) {
        if (v[i] == c) {
            count++;
        }
    }
    for (int i = 0; i < count; i++) {
        printf("%c", c);
    }
    return 0;
}
